async (params, browser) => {
  // Open Jira
  await browser.open(`${params.jira_url}/browse`)

  // Let Jira load
  await browser.wait(2000)

  // Search issues via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const jql = params.jql; const resp = await fetch(baseUrl + '/rest/api/3/search?jql=' + encodeURIComponent(jql) + '&maxResults=20&fields=summary,status,assignee,priority,issuetype,created,updated', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Jira API error: ' + resp.status); const data = await resp.json(); const issues = (data.issues || []).map(i => ({ key: i.key, summary: i.fields.summary, status: i.fields.status?.name || '', assignee: i.fields.assignee?.displayName || 'Unassigned', priority: i.fields.priority?.name || '', type: i.fields.issuetype?.name || '', created: i.fields.created, updated: i.fields.updated })); return { total: data.total, result_count: issues.length, issues: issues }`)

  return result
}
